SELECT population_count
FROM state_demographics
WHERE state_id = 0 AND race_id = 1;

SELECT SUM(population_count) AS total_population
FROM state_demographics
WHERE race_id = 1;

SELECT population_count, median_age
FROM county_demographics
WHERE county_id = 1;

SELECT race_name, description
FROM racial_categories
WHERE parent_category = 'Asian';

SELECT race_origin
FROM population_estimates
WHERE year = 2021;

SELECT race_id, SUM(population_count) AS total_population
FROM state_demographics
GROUP BY race_id;

SELECT race_id, SUM(population_count) AS total_population
FROM county_demographics
GROUP BY race_id;

SELECT MAX(population_count) AS max_population
FROM county_demographics
WHERE county_id = 0 AND race_id = 1;

SELECT race_origin, SUM(population_number) AS total_population
FROM population_estimates
GROUP BY race_origin;

SELECT race_name
FROM racial_categories
WHERE race_id = 1;

SELECT race_name, description
FROM racial_categories
ORDER BY race_name ASC;
